export const fillNarrative = (language, key, params = {}) => {
  let text = NARRATIVE_TRANSLATIONS[language]?.[key] || NARRATIVE_TRANSLATIONS.es[key] || key;
  Object.entries(params).forEach(([name, value]) => { text = text.replaceAll(`{${name}}`, value); });
  return text;
};

