export const translateUI = (language, key) => UI_TRANSLATIONS[language]?.[key] || UI_TRANSLATIONS.es[key] || MVP_TRANSLATIONS[language]?.[key] || MVP_TRANSLATIONS.es[key] || key;
export const translateStatus = (language, value) => STATUS_TRANSLATIONS[language]?.[value] || value;
export const getMeasurementConfidenceMessage = (language, status) => translateUI(language, status === 'good' ? 'measurementGood' : status === 'warning' ? 'measurementWarning' : 'measurementDanger');
